public enum TransactionIsolationLevel
{
    ReadCommitted = 0,
    ReadUncommitted = 1,
    RepeatableRead = 2,
    Serializable = 3,
    Snapshot = 4
}

public class EventBookingService
{
    private readonly DbContextOptions<EventBookingDbContext> _options;

    public EventBookingService(DbContextOptions<EventBookingDbContext> options)
    {
        _options = options;
    }

    public async Task<TicketPurchaseResult> PurchaseTickets(int eventId, int quantity)
    {
        using (var transactionScope = new TransactionScope(TransactionIsolationLevel.ReadCommitted))
        {
            try
            {
                var context = new EventBookingDbContext(_options);

                var eventItem = await context.Events.FindAsync(eventId);
                if (eventItem == null || eventItem.Seats < quantity)
                {
                    throw new Exception("Invalid ticket request");
                }

                using (var transaction = context.Database.BeginTransaction())
                {
                    try
                    {
                        eventItem.Seats -= quantity;

                        await context.SaveChangesAsync();

                        transaction.Commit();
                    }
                    catch
                    {
                        transaction.Rollback();
                        throw;
                    }
                }

                return new TicketPurchaseResult
                {
                    Success = true,
                    QuantityPurchased = quantity
                };
            }
            catch (Exception ex)
            {
                transactionScope Rollback();
                throw ex;
            }
        }
    }
}

